package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private Reader mockReader;

    @BeforeEach
    public void setUp() {
        mockReader = mock(Reader.class);
    }

    @Test
    public void testParse_ReturnsCSVParserInstance() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to create a mock CSVParser instance
        Constructor<CSVParser> constructor = CSVParser.class.getDeclaredConstructor(Reader.class, CSVFormat.class);
        constructor.setAccessible(true);

        CSVParser mockParser = mock(CSVParser.class);

        // Instead of mocking construction (not available), spy on CSVFormat and override parse method
        CSVFormat spyFormat = spy(format);

        doReturn(mockParser).when(spyFormat).parse(mockReader);

        // Call parse method on spy to get the mocked parser
        CSVParser parser = spyFormat.parse(mockReader);

        assertNotNull(parser);
        assertTrue(parser instanceof CSVParser);
        assertSame(mockParser, parser);
    }

    @Test
    public void testParse_NullReader_ThrowsNullPointerException() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertThrows(NullPointerException.class, () -> format.parse(null));
    }

}
